#include<cstdio>
#include<vector>
#include<map>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e5+10;std::vector<int> G[N],T[N];
int n,m,tot[N],deg[N],scc[N],top,stk[N],dfn[N],low[N];bool iss[N];
std::map<int,bool> vs[N];int cdt,cnt;
inline void tarjan(int u)
{
	dfn[u]=low[u]=++cdt;iss[stk[++top]=u]=true;
	for(int v:G[u])if(!dfn[v])tarjan(v),low[u]=min(low[u],low[v]);
	else if(iss[v])low[u]=min(low[u],low[v]);
	if(low[u]==dfn[u]){++cnt;int v;do iss[v=stk[top--]]=false,++tot[scc[v]=cnt];while(v!=u);}
}
int main()
{
//	FIN("data.in");
//	FOUT("mine.out");
	n=read();m=read();
	rep(1,m,i){int x=read(),y=read();G[x].push_back(y);}
	rep(1,n,i)if(!dfn[i])tarjan(i);
	rep(1,n,u)for(int v:G[u])
	{
		int U=scc[u],V=scc[v];if(U==V||vs[U].count(V))continue;
		vs[U][V]=true;++deg[V];T[U].push_back(V);
	}
//	rep(1,n,i)printf("%d ",scc[i]);
//	rep(1,n,i)printf("%d ",deg[i]);
	int c=0;bool flag=0;
	rep(1,cnt,u)if(!deg[u])
	{
		++c;if(tot[u]==1&&!flag)
		{
			bool qwq=false;
			for(int v:T[u]){if(deg[v]<=1){qwq=true;break;}}
			if(!qwq){--c;flag=true;}
		}
	}
	printf("%.6lf\n",1.-1.*c/n);
}
